<template>
  <div class="product">
    <ul class="products container">
      <li v-for="(item,index) in products" :key="index" :id="item.name">
        <router-link :to="'/product/'+item.id">
          <img :src="`../../../static/img/services/${item.icon}`" />
          <p class="mb-10 mt-30">{{ item.title }}</p>
        </router-link>
				<div class="detail">
					<img class="img_wrapper" :src="`../../../static/img/product/${item.img}`" alt="">
					<div class="desc">
            <p>{{ item.info }}</p>
          </div>
					<router-link :to="'/product/'+item.id" class="buy">
					<!-- <div class="desc"> -->
						<p class="desc">立即使用 >> </p>
					<!-- </div> -->
					</router-link>
					
				</div>
      </li>
    </ul>
  </div>
</template>
<script>
export default {
  name: "product",
  data() {
    return {
      category: [
        {
          kind: 0,
          title: "所有",
          color: "#2F4056"
        },
        {
          kind: 1,
          title: "移动手机",
          color: "#009688"
        },
        {
          kind: 2,
          title: "动态住宅",
          color: "#5FB878"
        },
        {
          kind: 3,
          title: "静态住宅",
          color: "#ff8724"
        },
        {
          kind: 4,
          title: "机房服务器",
          color: "#9d0b23"
        }
      ],
      products: [
        {
          id: 1,
					kind: 1,
					name: "shouji",
					icon: "shouji.png",
					img: "test.png",
          title: "手机代理",
          info:
            "移动手机IP使用非常方便，只需几分钟，您就可以通过API接口或客户端获取代理IP并参照代码样例使用到业务中。"
        },
        {
          id: 2,
          kind: 2,
					name: "dongtai",
          icon: "dongtai.png",
					img: "jingtai.png",
          title: "动态住宅",
          info:
            "Lucproxy提供超过2000万IP的住宅代理服务，响应时间短、数据传输速度快。移动手机IP使用非常方便，只需几分钟，您就可以通过API接口或客户端获取代理IP并参照代码样例使用到业务中"
        },
        {
          id: 3,
					kind: 3,
					name: "jingtai",
          icon: "jingtai.png",
					img: "test.png",
          title: "静态住宅",
          info:
            "Lucproxy提供全球静态住宅IP的网络超过100万， 您能够在全球多个国家拥有真实的IP，连通速度极快100%在线。\n 静态住宅IP使用非常方便，只需几分钟，您就可以通过API接口或客户端获取代理IP并参照代码样例使用到业务中"
        },
        {
          id: 4,
          kind: 4,
					name: "jifang",
          icon: "jifang.png",
					img: "jingtai.png",
          title: "机房中心",
          info: "Lucproxy提供基于云主机构建的高品质代理服务器，为您提供高速、可信赖的网络代理服务。服务器代理每天可用IP数量超过10万个，可用率在95%以上，1次可提取IP数量超过50个，可以为您的业务提供强大的助力。服务器代理使用非常方便，只需几分钟，您就可以通过API接口或客户端获取代理IP并参照代码样例使用到业务中"
        }
      ],
      copy_products: []
    };
  },
  created() {
    this.$emit("headFix", ["relative", false, "rgba(3,3,3,.8)"]);
	},
	beforeRouteUpdate (to, from, next) {
		this.goAnchor(to.hash)
		next();
  },
  mounted() {
		this.goAnchor(this.$route.hash)
    this.copy_products = JSON.parse(JSON.stringify(this.products));
  },
  methods: {
    selected(item) {
      if (item.kind == 0) {
        this.products = this.copy_products;
      } else {
        this.products = this.copy_products.filter(it => it.kind === item.kind);
      }
		},
		goAnchor(hash) {
			if (hash.length == 0) {
				return
			}
			//获取元素
			let anchor = this.$el.querySelector(hash);
    	if(anchor) {
        setTimeout( () => {
					//页面没有渲染完成时是无法滚动的，因此设置延迟
					//js的内置方法，可滚动视图位置至元素位置
          anchor.scrollIntoView(); 
				},300);
			}
    } 
  }
};
</script>
<style lang="scss" scoped>
.container {
  padding: 0 10%;
}

.mb-10 {
  margin-bottom: 0.625rem !important;
}

.mt-30 {
  margin-top: 1.875rem !important;
}

.product {
  padding-top: 5%;
  // background-color: #eefaff; // #393D49;

  .products {

    display: flex;
    flex-direction: column;
    align-items: flex-start;
		.desc {
			color: #13497f;
			font-size: 0.875rem;
			font-style: normal;
			font-weight: 400;
			line-height: 1.5rem;
			font-size: 0.875rem !important;
			font-weight: 300;
			text-align: left;
		}

    li {
      display: flex;
			align-items: center;
      a {
				// flex: 1;
        display: flex;
        flex-direction: column;
        align-items: center;
        color: #13497f;
        font-size: 1.125rem;
      }
			.detail{
				// flex: 2 1 auto;

				margin-left: 30px;;

        display: flex;
        flex-direction: column;
				align-items: flex-start;
				text-align: left;
			
				img{
					width: 80%;
				}
				p{
					padding: 20px 0;
				}
				.buy{
					width: 80%;
					text-align: center;
				}
			}
    }
  }
}
// 动画
@keyframes self-zoomIn {
  from {
    border: 0px solid transparent;
    transform: scale3d(0.3, 0.3, 0.3);
  }

  50% {
    border: 3px solid #ffffff;
  }

  80% {
    border: 3px solid #ffffff;
  }

  100% {
    border: 3px solid rgba(255, 255, 255, 0.4);
  }
}
</style>



